    'ion_cannon' => [
        'title' => 'Ion Cannon',
        'description' => 'The Ion Cannon fires a continuous beam of accelerating ions, causing considerable damage to objects it strikes.',
        'description_long' => 'Ionikanuuna on ase, joka ampuu ionisäteitä (positiivisesti tai negatiivisesti varautuneita hiukkasia). Ion Cannon on itse asiassa eräänlainen hiukkaskatuoni; vain käytetyt hiukkaset ovat ionisoituja. Sähkövaraustensa vuoksi ne voivat myös poistaa käytöstä elektroniset laitteet ja kaikki muut, joissa on sähköinen tai vastaava virtalähde, käyttämällä ilmiötä, joka tunnetaan nimellä Electromagetic Pulse (EMP-ilmiö). Kanuunoiden erittäin parannetun suojausjärjestelmän ansiosta tämä tykki tarjoaa paremman suojan suuremmille, tuhoisammille puolustusaseillesi. 

Taistelun jälkeen on jopa 70 % todennäköisyys, että epäonnistuneet puolustustilat voidaan palauttaa käyttöön.',
    ],
    'plasma_turret' => [
        'title' => 'Plasma Turret',
        'description' => 'Plasma Turrets release the energy of a solar flare and surpass even the destroyer in destructive effect.',
        'description_long' => 'Yksi kehittyneimmistä puolustusasejärjestelmistä, joka on koskaan kehitetty, Plasma Turret käyttää suurta ydinreaktorin polttokennoa sähkömagneettisen kiihdytin, joka laukaisee plasmapulssin tai toroidin. Käytön aikana plasmatorni lukittuu ensin maaliin ja aloittaa laukaisuprosessin. Tornien ytimeen syntyy plasmapallo ylikuumentamalla ja puristamalla kaasuja poistaen niistä ionejaan. Kun kaasu on tulistettu, puristettu ja plasmapallo on luotu, se ladataan sitten sähkömagneettiseen kiihdyttimeen, joka saa virtaa. Kun kiihdytin on aktivoitu täysin, se aktivoituu, mikä johtaa siihen, että plasmapallo laukeaa erittäin suurella nopeudella aiottuun kohteeseen. Kohteiden näkökulmasta lähestyvä sinertävä plasmapallo on vaikuttava, mutta kun se iskee, se aiheuttaa välittömän tuhon. 

Puolustustilat deaktivoituvat heti, kun ne ovat vaurioituneet liian voimakkaasti. Taistelun jälkeen on jopa 70 % todennäköisyys, että epäonnistuneet puolustustilat voidaan palauttaa käyttöön.',
    ],
    'small_shield_dome' => [
        'title' => 'Small Shield Dome',
        'description' => 'The small shield dome covers an entire planet with a field which can absorb a tremendous amount of energy.',
        'description_long' => 'Uusien maailmojen kolonisointi aiheutti uuden vaaran, avaruusromun. Suuri asteroidi voisi helposti pyyhkiä pois maailman ja kaikki sen asukkaat. Suojaustekniikan edistyminen tarjosi tutkijoille tavan kehittää kilpi, joka suojelee koko planeettaa paitsi avaruusromuilta, myös, kuten opittiin, vihollisen hyökkäykseltä. Luomalla suuri sähkömagneettinen kenttä planeetan ympärille, avaruusromut, jotka normaalisti olisivat tuhonneet planeetan, käännettiin pois ja vihollisvaltakuntien hyökkäykset estettiin. Ensimmäiset generaattorit olivat suuria ja kilpi tarjosi kohtuullisen suojan, mutta myöhemmin havaittiin, että pienet kilvet eivät antaneet suojaa suuremmilta hyökkäyksiltä. Pieni kilpikupoli oli alkusoitto vahvemmalle, kehittyneemmälle planeetan suojausjärjestelmälle. 

Taistelun jälkeen on jopa 70 % todennäköisyys, että epäonnistuneet puolustustilat voidaan palauttaa käyttöön.',
    ],
    'large_shield_dome' => [
        'title' => 'Large Shield Dome',
        'description' => 'The evolution of the small shield dome can employ significantly more energy to withstand attacks.',
        'description_long' => 'Large Shield Dome on seuraava askel planetaaristen kilpien kehityksessä, se on tulosta vuosien työstä Small Shield Dome -kupolin parantamiseksi. Suuret kupolit, jotka on rakennettu kestämään suurempia vihollisen tulipaloja tarjoamalla korkeamman sähkömagneettisen kentän, tarjoavat pidemmän suojan ennen romahtamista. 

Taistelun jälkeen on jopa 70 % todennäköisyys, että epäonnistuneet puolustustilat voidaan palauttaa käyttöön.',
    ],
    'anti_ballistic_missile' => [
        'title' => 'Anti-Ballistic Missiles',
        'description' => 'Anti-Ballistic Missiles destroy attacking interplanetary missiles',
        'description_long' => 'Anti Ballistiset ohjukset (ABM) ovat ainoa puolustuslinjasi, kun planeetallasi tai kuussasi hyökkäävät planeettojenväliset ohjukset (IPM). Kun IPM:n laukaisu havaitaan, nämä ohjukset virittyvät automaattisesti, käsittelevät laukaisukoodin lentotietokoneissaan, kohdistavat saapuvan IPM:n ja laukaisevat siepatakseen. Lennon aikana kohde-IPM:ää seurataan jatkuvasti ja kurssikorjauksia sovelletaan, kunnes ABM saavuttaa kohteen ja tuhoaa hyökkäävän IPM:n. Jokainen ABM tuhoaa yhden saapuvan IPM:n.',
    ],
    'interplanetary_missile' => [
        'title' => 'Interplanetary Missiles',
        'description' => 'Planeettojenväliset ohjukset tuhoavat vihollisen puolustuksen.',
        'description_long' => 'Interplanetaariset ohjukset (IPM) ovat hyökkäävä aseesi tuhotaksesi kohteensi puolustuksen. Uusinta seurantatekniikkaa käyttämällä jokainen ohjus kohdistaa tietyn määrän puolustusta tuhoamista varten. Anti-ainepommin kärjessä ne tuottavat niin ankaran tuhovoiman, että tuhoutuneita kilpiä ja puolustusta ei voida korjata. Ainoa tapa torjua näitä ohjuksia on ABM:illä.',
    ],
